class Solution:
    def rearrangeCharacters(self, s: str, target: str) -> int:
        s_count = {}
        for char in s:
            if char in s_count:
                s_count[char] += 1
            else:
                s_count[char] = 1

        target_count = {}
        for char in target:
            if char in target_count:
                target_count[char] += 1
            else:
                target_count[char] = 1

        max_copies = float('inf')
        for char, count in target_count.items():
            if char in s_count:
                max_copies = min(max_copies, s_count[char] // count)
            else:
                return 0

        return max_copies
```
efficiency: HIGH
time complexity: O(n + m)
space complexity: O(n + m)
